        for row in range(3, 5):
            for col in range(0, 8, 2):
                board[row][col] = "W"
            for col in range(1, 8, 2):
                board[7 - row][col] = "B"
        return board

    def print_board(self):
        # Print the current state of the board
        for row in self.board:
            print(" ".join(row))

    def is_valid_move(self, start, end):
        # Check if a move from start to end is valid
        piece = self.board[start[0]][start[1]]
        target = self.board[end[0]][end[1]]

        if piece == " " or piece.islower() != (self.current_player_index == 0):
            return False

        dx, dy = end[0] - start[0], end[1] - start[1]
        if abs(dx) not in [1, 2] or abs(dy) not in [1, 0]:
            return False

        if abs(dx) == 1:
            if target != " ":
                return False
        elif abs(dx) == 2:
            mid_piece = self.board[(start[0] + end[0]) // 2][(start[1] + end[1]) // 2]
            if mid_piece == " " or mid_piece.islower() == (self.current_player_index == 0):
                return False

        return True

